/*
 * fpclassifyf() test harness — prints (input_hex, classification) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fpclassifyf  (test_fpclassifyf_opt.elf)
 *   2. Linked with toolchain's default fpclassifyf        (test_fpclassifyf_ref.elf)
 * Run both, diff the output to find discrepancies.
 *
 * FP_ZERO=0, FP_SUBNORMAL=2, FP_NORMAL=4, FP_INFINITE=1, FP_NAN=3
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile int g_acc;

static void emit(float x)
{
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += fpclassify(vx);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit(float x)
{
    printf("%08lx %d\n", (unsigned long)f2u(x), fpclassify(x));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);                         /* +0: FP_ZERO */
    emit(-0.0f);                        /* -0: FP_ZERO */
    emit_u(0x7fc00000u);                /* +qNaN: FP_NAN */
    emit_u(0x7f800001u);                /* +sNaN: FP_NAN */
    emit_u(0xffc00000u);                /* -qNaN: FP_NAN */
    emit_u(0x7f800000u);                /* +Inf: FP_INFINITE */
    emit_u(0xff800000u);                /* -Inf: FP_INFINITE */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);                /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);                /* min negative subnormal: -2^-149 */
    emit_u(0x00400000u);                /* mid positive subnormal */
    emit_u(0x80400000u);                /* mid negative subnormal */
    emit_u(0x007fffffu);                /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);                /* max negative subnormal */

    /* --- Section 3: Normal boundary values (8) --- */
    emit(FLT_MIN);                      /* 0x00800000: smallest positive normal */
    emit(-FLT_MIN);                     /* 0x80800000: smallest negative normal */
    emit_u(0x00800001u);                /* one ULP above FLT_MIN */
    emit_u(0x80800001u);                /* one ULP above -FLT_MIN (toward zero) */
    emit(FLT_MAX);                      /* 0x7f7fffff: largest positive normal */
    emit(-FLT_MAX);                     /* 0xff7fffff: largest negative normal */
    emit_u(0x7f7ffffeu);                /* one ULP below FLT_MAX */
    emit_u(0xff7ffffeu);                /* one ULP below -FLT_MAX (toward zero) */

    /* --- Section 4: Near 1.0 (ULP density region) (8) --- */
    emit_u(0x3f7fffffu);                /* one ULP below 1.0f */
    emit(1.0f);                         /* 0x3f800000: 1.0 */
    emit_u(0x3f800001u);                /* one ULP above 1.0f */
    emit_u(0x3f7ffff0u);                /* a few ULPs below 1.0f */
    emit_u(0x3f800010u);                /* a few ULPs above 1.0f */
    emit(-1.0f);                        /* 0xbf800000: -1.0 */
    emit_u(0xbf7fffffu);                /* one ULP toward zero from -1.0f */
    emit_u(0xbf800001u);                /* one ULP away from zero from -1.0f */

    /* --- Section 5: Powers-of-2 exponent switching points (10) --- */
    emit(0.5f);                         /* 0x3f000000: 2^-1 */
    emit(-0.5f);                        /* 0xbf000000: -2^-1 */
    emit(2.0f);                         /* 0x40000000: 2^1 */
    emit(-2.0f);                        /* 0xc0000000: -2^1 */
    emit(4.0f);                         /* 0x40800000: 2^2 */
    emit(-4.0f);                        /* 0xc0800000: -2^2 */
    emit(0.25f);                        /* 0x3e800000: 2^-2 */
    emit(-0.25f);                       /* 0xbe800000: -2^-2 */
    emit(0.125f);                       /* 0x3e000000: 2^-3 */
    emit(-0.125f);                      /* 0xbe000000: -2^-3 */

    /* --- Section 6: Additional NaN payload patterns (8) --- */
    emit_u(0x7fffffffu);                /* quiet NaN with all-ones mantissa */
    emit_u(0xffffffffu);                /* negative quiet NaN with all-ones mantissa */
    emit_u(0x7fc12345u);                /* quiet NaN with arbitrary payload */
    emit_u(0xffc12345u);                /* negative quiet NaN with arbitrary payload */
    emit_u(0x7f812345u);                /* signaling NaN with arbitrary payload */
    emit_u(0xff812345u);                /* negative signaling NaN with arbitrary payload */
    emit_u(0xff800001u);                /* -sNaN: minimal signaling NaN payload */
    emit_u(0x7f800002u);                /* +sNaN with payload=2 */

    /* --- Section 7: Class boundary transitions (20) --- */
    /* Positive: zero -> subnormal boundary */
    emit_u(0x00000000u);                /* +0: FP_ZERO */
    emit_u(0x00000002u);                /* second positive subnormal */
    /* Positive: subnormal -> normal boundary */
    emit_u(0x007ffffeu);                /* one below max positive subnormal */
    emit_u(0x00800000u);                /* FLT_MIN: min normal (same as FLT_MIN above but as bits) */
    /* Positive: normal -> infinity boundary */
    emit_u(0x7f7ffffdu);                /* two ULPs below FLT_MAX */
    emit_u(0x7f7fffffu);                /* FLT_MAX (max normal, same as FLT_MAX above as bits) */
    /* Note: 0x7f800000 = +Inf already in section 1 */
    /* Negative: zero -> subnormal boundary */
    emit_u(0x80000000u);                /* -0: FP_ZERO */
    emit_u(0x80000002u);                /* second negative subnormal */
    /* Negative: subnormal -> normal boundary */
    emit_u(0x807ffffeu);                /* one below max negative subnormal (toward zero) */
    emit_u(0x80800000u);                /* min negative normal */
    /* Negative: normal -> -infinity boundary */
    emit_u(0xff7ffffdu);                /* two ULPs below -FLT_MAX (toward -Inf) */
    emit_u(0xff7fffffu);                /* -FLT_MAX (max neg normal) */
    /* Note: 0xff800000 = -Inf already in section 1 */
    /* One ULP past infinities: signaling NaN territory */
    emit_u(0x7f800003u);                /* +sNaN just past +Inf */
    emit_u(0xff800003u);                /* -sNaN just past -Inf */
    /* Exponent field = 0xfe (max finite exponent) */
    emit_u(0x7f000000u);                /* 2^126: large normal */
    emit_u(0xff000000u);                /* -2^126: large negative normal */
    emit_u(0x01000000u);                /* 2^-126 = FLT_MIN (exponent=1, mantissa=0) same bits */
    /* Samples at exponent=1 and exponent=0xfe boundaries */
    emit_u(0x00ffffffu);                /* max value with exponent=0: subnormal */
    emit_u(0x80ffffffu);                /* negative max value with exponent=0: subnormal */
    emit_u(0x01800000u);                /* normal with exponent=3, mantissa nonzero */

    /* --- Section 8: Scattered normals across exponent range (15) --- */
    emit(1.5f);                         /* 0x3fc00000 */
    emit(-1.5f);                        /* 0xbfc00000 */
    emit(10.0f);                        /* 0x41200000 */
    emit(-10.0f);                       /* 0xc1200000 */
    emit(100.0f);                       /* 0x42c80000 */
    emit(-100.0f);                      /* 0xc2c80000 */
    emit(1000.0f);                      /* 0x447a0000 */
    emit(-1000.0f);                     /* 0xc47a0000 */
    emit_u(0x40490fdbu);                /* pi: 0x40490fdb */
    emit_u(0xc0490fdbu);                /* -pi: 0xc0490fdb */
    emit(1.0e10f);                      /* 0x501502f9: large normal */
    emit(-1.0e10f);                     /* 0xd01502f9: large negative normal */
    emit(1.0e20f);                      /* 0x60ad78ec: very large normal */
    emit(-1.0e20f);                     /* 0xe0ad78ec: very large negative normal */
    emit(1.0e-10f);                     /* 0x2edbe6ff: small normal */

    /* --- Section 9: Small subnormals and additional denormal coverage (8) --- */
    emit_u(0x00200000u);                /* positive subnormal, exponent=0, mantissa=0x200000 */
    emit_u(0x80200000u);                /* negative subnormal, exponent=0, mantissa=0x200000 */
    emit_u(0x00100000u);                /* positive subnormal, lower mantissa */
    emit_u(0x80100000u);                /* negative subnormal, lower mantissa */
    emit_u(0x00010000u);                /* positive subnormal, very small mantissa */
    emit_u(0x80010000u);                /* negative subnormal, very small mantissa */
    emit_u(0x00000010u);                /* positive subnormal, near-minimum mantissa */
    emit_u(0x80000010u);                /* negative subnormal, near-minimum mantissa */

    /* --- Section 10: Additional normals and boundary stress (10) --- */
    emit(8.0f);                         /* 0x41000000: 2^3 */
    emit(-8.0f);                        /* 0xc1000000: -2^3 */
    emit(16.0f);                        /* 0x41800000: 2^4 */
    emit(-16.0f);                       /* 0xc1800000: -2^4 */
    emit_u(0x3fc90fdbu);                /* pi/2: 0x3fc90fdb */
    emit_u(0xbfc90fdbu);                /* -pi/2: 0xbfc90fdb */
    emit_u(0x3f317218u);                /* ln2: 0x3f317218 */
    emit_u(0xbf317218u);                /* -ln2: 0xbf317218 */
    emit_u(0x42b17218u);                /* exp overflow threshold (~88.7): normal */
    emit_u(0xc2b17218u);                /* negative exp overflow threshold: normal */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %x\n", (unsigned)g_acc);
#else
    test_representative_100();
#endif
    return 0;
}
